from flask import Flask, request, jsonify
import redis

app = Flask(__name__)
r = redis.StrictRedis(host='localhost', port=6379, db=0)

@app.route('/execute', methods=['GET'])
def execute_redis_command():
    command = request.args.get('command', '')
    
    # Validate the command to prevent dangerous operations
    allowed_commands = {'GET', 'SET', 'DEL', 'EXISTS', 'EXPIRE', 'TTL', 'INCR', 'DECR'}
    command_parts = command.split()
    
    if not command_parts or command_parts[0].upper() not in allowed_commands:
        return jsonify({'error': 'Invalid or unauthorized command'}), 400
    
    try:
        # Execute the command safely
        result = r.execute_command(*command_parts)
        return jsonify({'result': result})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)